What does this program print?

```cpp
#include <iostream>

namespace a
{
    int value() { return 10; }
}

namespace b
{
    int value() { return 20; }
}

int main()
{
    std::cout << a::value() << "\n";
    std::cout << b::value() << "\n";
    return 0;
}
```

This program compiles but does not print what the programmer intended. The programmer wanted to call their own `add` function, which adds 1 to each argument before summing. What is the bug?

```cpp
#include <iostream>
using namespace std;

namespace utils
{
    int add(int a, int b) { return (a + 1) + (b + 1); }
}

int main()
{
    cout << add(3, 4) << "\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>

namespace math
{
    int square(int x) { return x * x; }
}

int main()
{
    std::cout << math::square(4) << "\n";
    std::cout << math::square(0) << "\n";
    return 0;
}
```
